  const ts = parseTs(row.requested_at ?? row.timestamp ?? row.executed_at ?? '');
  if (fromDate && (!ts || ts < fromDate)) return false;
  if (toDate && (!ts || ts > toDate)) return false;

  const rowResult = String(row.status ?? row.result ?? '').trim().toLowerCase();
  const rowRunMode = String(row.run_mode ?? '').trim().toLowerCase();
  const rowExecutionId = String(row.execution_id ?? '').trim();
  const rowCorrelationId = String(row.correlation_id ?? '').trim();

